index 9f034aba874a..e9e1ebe9cfb0 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp
@@ -3308,6 +3308,8 @@ Instruction *InstCombinerImpl::foldICmpBinOpEqualityWithConstant(
   if (!Cmp.isEquality())
     return nullptr;

+  errs() << "foldICmpBinOpEqualityWithConstant C=" << C << "\n";
+
   ICmpInst::Predicate Pred = Cmp.getPredicate();
   bool isICMP_NE = Pred == ICmpInst::ICMP_NE;
   Constant *RHS = cast<Constant>(Cmp.getOperand(1));
@@ -3326,13 +3328,50 @@ Instruction *InstCombinerImpl::foldICmpBinOpEqualityWithConstant(
     }
     break;
   case Instruction::Add: {
+    // (A + C2) == C --> A == (C - C2)
+    // (A + C2) != C --> A != (C - C2)
+    // TODO: Remove the one-use limitation? See discussion in D58633.
     // (A + C2) == C --> A == (C - C2)
     // (A + C2) != C --> A != (C - C2)
     // TODO: Remove the one-use limitation? See discussion in D58633.
     if (Constant *C2 = dyn_cast<Constant>(BOp1)) {
       if (BO->hasOneUse())
         return new ICmpInst(Pred, BOp0, ConstantExpr::getSub(RHS, C2));
-    } else if (C.isZero()) {
+    }
+    // Check for boolean adds: (zext i1 A) + (zext i1 B)
+    Value *A, *B;
+    if (match(BOp0, m_ZExt(m_Value(A))) && A->getType()->getScalarSizeInBits() == 1 &&
+        match(BOp1, m_ZExt(m_Value(B))) && B->getType()->getScalarSizeInBits() == 1) {
+      // The sum of two booleans is in {0,1,2}.
+      if (C.isZero()) {
+        // (zext i1 A) + (zext i1 B) == 0 --> (A | B) == 0
+        // (zext i1 A) + (zext i1 B) != 0 --> (A | B) != 0
+        Value *Or = Builder.CreateOr(A, B);
+        return new ICmpInst(Pred, Or, ConstantInt::get(Or->getType(), 0));
+      }
+      if (C.isOne()) {
+        // (zext i1 A) + (zext i1 B) == 1 --> xor A, B
+        // (zext i1 A) + (zext i1 B) != 1 --> not (xor A, B)
+        Value *Xor = Builder.CreateXor(A, B);
+        if (Pred == ICmpInst::ICMP_EQ)
+          return replaceInstUsesWith(Cmp, Xor);
+        // ICMP_NE
+        return BinaryOperator::CreateNot(Xor);
+      }
+      if (C.getZExtValue() == 2) {
+        // (zext i1 A) + (zext i1 B) == 2 --> A & B
+        // (zext i1 A) + (zext i1 B) != 2 --> not (A & B)
+        Value *And = Builder.CreateAnd(A, B);
+        if (Pred == ICmpInst::ICMP_EQ)
+          return replaceInstUsesWith(Cmp, And);
+        // ICMP_NE
+        return BinaryOperator::CreateNot(And);
+      }
+      // For other constants (e.g., 3) the result is always false (for equality)
+      // but we let other folds handle that.
+    }
+    // Generic handling for zero constant when add operands are not booleans.
+    if (C.isZero()) {
       // Replace ((add A, B) != 0) with (A != -B) if A or B is
       // efficiently invertible, or if the add has just this one use.
